import{_ as s,o as e,c as n,ag as t}from"./chunks/framework.Cqf6AMW8.js";const m=JSON.parse('{"title":"STM32 工程复用","description":"STM32 工程复用的步骤和注意事项。","frontmatter":{"title":"STM32 工程复用","description":"STM32 工程复用的步骤和注意事项。","date":"2026-04-21T00:00:00.000Z","tags":["STM32","工程复用"],"sidebar":"auto"},"headers":[],"relativePath":"docs/hardware/stm32/stm32-1-工程复用.md","filePath":"docs/hardware/stm32/stm32-1-工程复用.md","lastUpdated":1776715536000}'),l={name:"docs/hardware/stm32/stm32-1-工程复用.md"};function i(p,a,d,o,c,r){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="stm32" tabindex="-1">STM32 <a class="header-anchor" href="#stm32" aria-label="Permalink to &quot;STM32&quot;">​</a></h1><p>======================================================</p><h2 id="stm32工程复用" tabindex="-1">STM32工程复用 <a class="header-anchor" href="#stm32工程复用" aria-label="Permalink to &quot;STM32工程复用&quot;">​</a></h2><h2 id="_1-复用步骤" tabindex="-1">1. 复用步骤 <a class="header-anchor" href="#_1-复用步骤" aria-label="Permalink to &quot;1. 复用步骤&quot;">​</a></h2><h3 id="_1-1-添加组并添加组内文件" tabindex="-1">1.1 添加组并添加组内文件 <a class="header-anchor" href="#_1-1-添加组并添加组内文件" aria-label="Permalink to &quot;1.1 添加组并添加组内文件&quot;">​</a></h3><ul><li><p><strong>Start 组</strong>：添加启动文件和核心系统文件</p><ul><li><code>startup_stm32f10x_md.s</code>（根据芯片容量选择对应的启动文件）</li><li><code>core_cm3.h</code></li><li><code>stm32f10x.h</code></li><li><code>system_stm32f10x.c</code></li><li><code>system_stm32f10x.h</code></li></ul></li><li><p><strong>Library 组</strong>：添加 STM32 标准库文件</p><ul><li>所有标准库 <code>.c</code> 和 <code>.h</code> 文件（如 <code>stm32f10x_gpio.c</code>、<code>stm32f10x_usart.c</code> 等）</li></ul></li><li><p><strong>System 组</strong>：添加用户自己编写的库文件</p><ul><li>用户自定义的驱动模块</li><li>用户自定义的功能模块 <code>.c</code> 和 <code>.h</code> 文件</li></ul></li><li><p><strong>User 组</strong>：添加用户代码文件</p><ul><li><code>main.c</code></li><li>其他用户应用程序文件</li></ul></li></ul><p>======================================================</p><h3 id="_1-2-添加组路径" tabindex="-1">1.2 添加组路径 <a class="header-anchor" href="#_1-2-添加组路径" aria-label="Permalink to &quot;1.2 添加组路径&quot;">​</a></h3><p>在 Keil 的「C/C++」选项卡中，添加包含路径：</p><ul><li><code>./Start</code></li><li><code>./Library</code></li><li><code>./System</code></li><li><code>./User</code></li></ul><p>======================================================</p><h3 id="_1-3-添加宏声明" tabindex="-1">1.3 添加宏声明 <a class="header-anchor" href="#_1-3-添加宏声明" aria-label="Permalink to &quot;1.3 添加宏声明&quot;">​</a></h3><p>在 Keil 的「C/C++」选项卡的「Define」栏中，添加宏定义：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>USE_STDPERIPH_DRIVER</span></span></code></pre></div><p>======================================================</p><h3 id="_1-4-配置调试器" tabindex="-1">1.4 配置调试器 <a class="header-anchor" href="#_1-4-配置调试器" aria-label="Permalink to &quot;1.4 配置调试器&quot;">​</a></h3><p>在 Keil 的「Debug」选项卡中：</p><ul><li>选择调试器：<strong>ST-Link Debugger</strong></li><li>在「Flash Download」中勾选「Reset and Run」</li></ul><p>======================================================</p><h2 id="_2-工程目录结构" tabindex="-1">2. 工程目录结构 <a class="header-anchor" href="#_2-工程目录结构" aria-label="Permalink to &quot;2. 工程目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project/</span></span>
<span class="line"><span>├── Start/</span></span>
<span class="line"><span>│   ├── core_cm3.h</span></span>
<span class="line"><span>│   ├── startup_stm32f10x_md.s</span></span>
<span class="line"><span>│   ├── stm32f10x.h</span></span>
<span class="line"><span>│   ├── system_stm32f10x.c</span></span>
<span class="line"><span>│   └── system_stm32f10x.h</span></span>
<span class="line"><span>├── Library/</span></span>
<span class="line"><span>│   ├── misc.c</span></span>
<span class="line"><span>│   ├── misc.h</span></span>
<span class="line"><span>│   ├── stm32f10x_adc.c</span></span>
<span class="line"><span>│   ├── stm32f10x_adc.h</span></span>
<span class="line"><span>│   └── ...（其他标准库文件）</span></span>
<span class="line"><span>├── System/</span></span>
<span class="line"><span>│   ├── 用户自定义库文件.c</span></span>
<span class="line"><span>│   └── 用户自定义库文件.h</span></span>
<span class="line"><span>├── User/</span></span>
<span class="line"><span>│   └── main.c</span></span>
<span class="line"><span>└── project.uvoptx</span></span>
<span class="line"><span>└── project.uvprojx</span></span></code></pre></div><p>======================================================</p><h2 id="_3-注意事项" tabindex="-1">3. 注意事项 <a class="header-anchor" href="#_3-注意事项" aria-label="Permalink to &quot;3. 注意事项&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注意事项</th><th>详细说明</th></tr></thead><tbody><tr><td>启动文件选择</td><td>根据芯片容量选择正确的启动文件：ld（小容量）、md（中容量）、hd（大容量）、xl（加大容量）</td></tr><tr><td>标准库文件</td><td>确保添加了所有必要的标准库文件</td></tr><tr><td>System 组</td><td>用于存放用户自己编写的库文件，便于模块化管理和复用</td></tr><tr><td>包含路径配置</td><td>配置正确的包含路径，否则会出现头文件找不到的错误</td></tr></tbody></table>`,24)])])}const u=s(l,[["render",i]]);export{m as __pageData,u as default};
